function initializeWithPreloadedData() {
    const DATA_VERSION = 'v10_1646';
    const VERSION_KEY = 'fleet_data_version';
    const existingDB = localStorage.getItem('fleet_maintenance_db');
    const storedVersion = localStorage.getItem(VERSION_KEY);
    
    // First visit - no data at all
    if (!existingDB) {
        localStorage.setItem('fleet_maintenance_db', JSON.stringify(INITIAL_FLEET_DATA));
        localStorage.setItem(VERSION_KEY, DATA_VERSION);
        console.log('Database initialized with pre-loaded fleet data');
        return true;
    }
    
    // Already merged this version - never touch user data again
    if (storedVersion === DATA_VERSION) {
        return false;
    }
    
    try {
        const parsed = JSON.parse(existingDB);
        if (!parsed.vehicles || parsed.vehicles.length === 0) {
            localStorage.setItem('fleet_maintenance_db', JSON.stringify(INITIAL_FLEET_DATA));
            localStorage.setItem(VERSION_KEY, DATA_VERSION);
            console.log('Empty database replaced with pre-loaded fleet data');
            return true;
        }
        
        // One-time merge for new data version
        console.log('New data version detected - merging once...');
        
        const existingMap = new Map();
        parsed.vehicles.forEach(v => existingMap.set(v.reg, v));
        
        INITIAL_FLEET_DATA.vehicles.forEach(pv => {
            const ev = existingMap.get(pv.reg);
            if (!ev) {
                parsed.vehicles.push({...pv});
            } else {
                const existingIds = new Set(ev.services.map(s => s.id));
                pv.services.forEach(ps => {
                    if (!existingIds.has(ps.id)) {
                        ev.services.push({...ps});
                    }
                });
                ev.services.sort((a, b) => new Date(b.date) - new Date(a.date));
                if (pv.initialMileage > ev.initialMileage) {
                    ev.initialMileage = pv.initialMileage;
                }
            }
        });
        
        parsed.lastUpdated = new Date().toISOString();
        localStorage.setItem('fleet_maintenance_db', JSON.stringify(parsed));
        localStorage.setItem(VERSION_KEY, DATA_VERSION);
        console.log('One-time merge complete - user edits will be preserved from now on');
        return true;
        
    } catch (e) {
        localStorage.setItem('fleet_maintenance_db', JSON.stringify(INITIAL_FLEET_DATA));
        localStorage.setItem(VERSION_KEY, DATA_VERSION);
        console.log('Invalid database replaced with pre-loaded fleet data');
        return true;
    }
}

// Function to merge original data with existing data (NEVER deletes user data)
function forceReloadFleetData() {
    if (confirm('This will MERGE the original fleet data with your current data.\n\nAll your records will be PRESERVED.\nOnly missing original vehicles/services will be added.\n\nContinue?')) {
        try {
            const existingDB = localStorage.getItem('fleet_maintenance_db');
            let currentData = { vehicles: [] };
            
            if (existingDB) {
                currentData = JSON.parse(existingDB);
            }
            
            // Create a map of existing vehicles by registration number
            const existingVehiclesMap = new Map();
            currentData.vehicles.forEach(v => {
                existingVehiclesMap.set(v.reg, v);
            });
            
            // Process each vehicle from INITIAL_FLEET_DATA
            INITIAL_FLEET_DATA.vehicles.forEach(originalVehicle => {
                const existingVehicle = existingVehiclesMap.get(originalVehicle.reg);
                
                if (!existingVehicle) {
                    // Vehicle doesn't exist - add it entirely
                    currentData.vehicles.push({...originalVehicle});
                    console.log(`Added missing vehicle: ${originalVehicle.reg}`);
                } else {
                    // Vehicle exists - merge services (add only missing ones)
                    const existingServiceIds = new Set(existingVehicle.services.map(s => s.id));
                    
                    originalVehicle.services.forEach(originalService => {
                        if (!existingServiceIds.has(originalService.id)) {
                            existingVehicle.services.push({...originalService});
                            console.log(`Added missing service to ${originalVehicle.reg}: ${originalService.work}`);
                        }
                    });
                    
                    // Sort services by date (newest first)
                    existingVehicle.services.sort((a, b) => new Date(b.date) - new Date(a.date));
                }
            });
            
            // Save merged data
            localStorage.setItem('fleet_maintenance_db', JSON.stringify(currentData));
            console.log('Data merged successfully - all user records preserved');
            
            alert('Data merged successfully!\nAll your records have been preserved.');
            location.reload();
            
        } catch (e) {
            console.error('Error merging data:', e);
            alert('Error merging data. Your current data was NOT modified.');
        }
    }
}

// Function to export current database as JSON file (backup)
function exportDatabaseBackup() {
    try {
        const db = localStorage.getItem('fleet_maintenance_db');
        if (!db) {
            alert('No data to export!');
            return;
        }
        
        const blob = new Blob([db], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        const date = new Date().toISOString().split('T')[0];
        a.href = url;
        a.download = `fleet_backup_${date}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        
        console.log('Database backup exported successfully');
    } catch (e) {
        console.error('Error exporting backup:', e);
        alert('Error creating backup file');
    }
}
